export interface GlossaryEntry {
  slug: string;
  term: { de: string; en: string; ru: string };
  definition: { de: string; en: string; ru: string };
  category: string;
  relatedTerms: string[];
  relatedServices: string[];
}

export const glossaryEntries: GlossaryEntry[] = [
  { slug: "achtsamkeit", term: { de: "Achtsamkeit", en: "Mindfulness", ru: "Осознанность" }, definition: { de: "Achtsamkeit ist die Fähigkeit, den gegenwärtigen Moment bewusst und ohne Bewertung wahrzunehmen. In der Führung ermöglicht sie klarere Entscheidungen und authentischere Beziehungen zu Mitarbeitern und Stakeholdern.", en: "Mindfulness is the ability to consciously perceive the present moment without judgment. In leadership, it enables clearer decisions and more authentic relationships with employees and stakeholders.", ru: "Осознанность — способность воспринимать настоящий момент сознательно и без оценки. В лидерстве она позволяет принимать более ясные решения и строить аутентичные отношения с сотрудниками." }, category: "bewusstsein", relatedTerms: ["praesenz", "bewusstsein", "meditation"], relatedServices: ["coaching", "seminare"] },
  { slug: "bewusstsein", term: { de: "Bewusstsein", en: "Consciousness", ru: "Сознание" }, definition: { de: "Bewusstsein bezeichnet die Gesamtheit unserer Wahrnehmung, Gedanken und Empfindungen. In Anatoly Mooks Arbeit wird Bewusstsein als Schlüssel zu persönlicher Meisterschaft und bewusster Führung verstanden — als Fundament für alle anderen Kompetenzen.", en: "Consciousness refers to the totality of our perception, thoughts, and sensations. In Anatoly Mook's work, consciousness is understood as the key to personal mastery and conscious leadership — as the foundation for all other competencies.", ru: "Сознание охватывает всю совокупность восприятия, мыслей и ощущений. В работе Анатолия Мука сознание понимается как ключ к личному мастерству и осознанному лидерству — как основа всех компетенций." }, category: "bewusstsein", relatedTerms: ["bewusstseinsentwicklung", "achtsamkeit", "selbstbewusstsein"], relatedServices: ["coaching", "seminare"] },
  { slug: "bewusstseinsentwicklung", term: { de: "Bewusstseinsentwicklung", en: "Consciousness Development", ru: "Развитие сознания" }, definition: { de: "Bewusstseinsentwicklung ist der gezielte Prozess, die eigene Wahrnehmungsfähigkeit zu erweitern. Sie ermöglicht tieferes Verständnis von sich selbst und anderen, bessere Entscheidungen und authentischeres Handeln in allen Lebensbereichen.", en: "Consciousness development is the deliberate process of expanding one's perceptual capacity. It enables deeper understanding of self and others, better decisions, and more authentic action in all areas of life.", ru: "Развитие сознания — целенаправленный процесс расширения способности восприятия. Оно даёт более глубокое понимание себя и других, лучшие решения и более аутентичные действия во всех сферах жизни." }, category: "bewusstsein", relatedTerms: ["bewusstsein", "selbsterkenntnis", "transformation"], relatedServices: ["coaching", "seminare"] },
  { slug: "gegenwaertigkeit", term: { de: "Gegenwärtigkeit", en: "Presence", ru: "Присутствие в моменте" }, definition: { de: "Gegenwärtigkeit ist die Qualität, vollständig im aktuellen Moment präsent zu sein. Führungskräfte mit hoher Gegenwärtigkeit sind aufmerksamer, empathischer und treffen Entscheidungen mit größerer Klarheit.", en: "Presence is the quality of being fully present in the current moment. Leaders with high presence are more attentive, empathetic, and make decisions with greater clarity.", ru: "Присутствие в моменте — качество полного пребывания в настоящем. Руководители с высоким присутствием внимательнее, эмпатичнее и принимают решения с большей ясностью." }, category: "bewusstsein", relatedTerms: ["praesenz", "achtsamkeit", "innere-klarheit"], relatedServices: ["coaching"] },
  { slug: "innere-klarheit", term: { de: "Innere Klarheit", en: "Inner Clarity", ru: "Внутренняя ясность" }, definition: { de: "Innere Klarheit ist der Zustand, in dem Gedanken, Gefühle und Handlungen in Einklang sind. Sie ermöglicht authentische Entscheidungen frei von Verwirrung und äußerem Druck — ein Kernelement in Anatoly Mooks Methode.", en: "Inner clarity is the state where thoughts, feelings, and actions are in alignment. It enables authentic decisions free from confusion and external pressure — a core element of Anatoly Mook's method.", ru: "Внутренняя ясность — состояние, когда мысли, чувства и действия находятся в гармонии. Она позволяет принимать аутентичные решения свободно от замешательства и внешнего давления." }, category: "bewusstsein", relatedTerms: ["bewusstsein", "achtsamkeit", "entscheidungsstaerke"], relatedServices: ["coaching", "seminare"] },
  { slug: "meditation", term: { de: "Meditation", en: "Meditation", ru: "Медитация" }, definition: { de: "Meditation ist eine Praxis der bewussten Aufmerksamkeitslenkung, die zu tieferer Ruhe und Klarheit führt. In der professionellen Anwendung stärkt sie Fokus, Stressresistenz und die Fähigkeit zu bewussten Entscheidungen.", en: "Meditation is a practice of conscious attention direction that leads to deeper calm and clarity. In professional application, it strengthens focus, stress resistance, and the ability to make conscious decisions.", ru: "Медитация — практика осознанного направления внимания, ведущая к глубокому покою и ясности. В профессиональном применении она укрепляет фокус, стрессоустойчивость и способность к осознанным решениям." }, category: "bewusstsein", relatedTerms: ["achtsamkeit", "praesenz", "innere-klarheit"], relatedServices: ["seminare"] },
  { slug: "praesenz", term: { de: "Präsenz", en: "Presence", ru: "Присутствие" }, definition: { de: "Präsenz beschreibt die Fähigkeit, mit voller Aufmerksamkeit im Hier und Jetzt zu sein. In Führungskontexten strahlt Präsenz Sicherheit und Vertrauen aus und ist Grundlage für wirkungsvolle Kommunikation.", en: "Presence describes the ability to be fully attentive in the here and now. In leadership contexts, presence radiates security and trust, forming the foundation for effective communication.", ru: "Присутствие описывает способность быть полностью внимательным здесь и сейчас. В контексте лидерства присутствие излучает безопасность и доверие, являясь основой эффективной коммуникации." }, category: "bewusstsein", relatedTerms: ["gegenwaertigkeit", "achtsamkeit", "authentische-fuehrung"], relatedServices: ["coaching", "keynotes"] },
  { slug: "selbstbewusstsein", term: { de: "Selbstbewusstsein", en: "Self-Awareness", ru: "Самосознание" }, definition: { de: "Selbstbewusstsein ist das Wissen um die eigenen Stärken, Schwächen, Werte und Muster. Es ist die Basis für persönliches Wachstum und bewusste Führung — ohne Selbstbewusstsein keine echte Transformation.", en: "Self-awareness is knowing your own strengths, weaknesses, values, and patterns. It is the foundation for personal growth and conscious leadership — without self-awareness, no true transformation.", ru: "Самосознание — знание собственных сильных и слабых сторон, ценностей и паттернов. Оно — основа личного роста и осознанного лидерства. Без самосознания нет настоящей трансформации." }, category: "bewusstsein", relatedTerms: ["bewusstsein", "selbsterkenntnis", "emotionale-intelligenz"], relatedServices: ["coaching"] },
  { slug: "authentische-fuehrung", term: { de: "Authentische Führung", en: "Authentic Leadership", ru: "Аутентичное лидерство" }, definition: { de: "Authentische Führung basiert auf Selbstkenntnis, Transparenz und wertebasiertem Handeln. Authentische Führungskräfte inspirieren durch Kongruenz zwischen Worten und Taten statt durch Macht oder Manipulation.", en: "Authentic leadership is based on self-knowledge, transparency, and values-based action. Authentic leaders inspire through congruence between words and deeds rather than through power or manipulation.", ru: "Аутентичное лидерство основано на самопознании, прозрачности и действиях на основе ценностей. Аутентичные лидеры вдохновляют через конгруэнтность слов и дел, а не через власть или манипуляции." }, category: "fuehrung", relatedTerms: ["bewusste-fuehrung", "integritaet", "servant-leadership"], relatedServices: ["coaching", "corporate"] },
  { slug: "bewusste-fuehrung", term: { de: "Bewusste Führung", en: "Conscious Leadership", ru: "Осознанное лидерство" }, definition: { de: "Bewusste Führung vereint Selbstkenntnis, Empathie und strategische Klarheit. Sie bedeutet, Entscheidungen reflektiert statt reaktiv zu treffen und Teams durch Präsenz und Vertrauen statt Kontrolle zu leiten.", en: "Conscious leadership combines self-knowledge, empathy, and strategic clarity. It means making decisions reflectively rather than reactively and guiding teams through presence and trust rather than control.", ru: "Осознанное лидерство объединяет самопознание, эмпатию и стратегическую ясность. Оно означает рефлективное принятие решений и ведение команд через присутствие и доверие, а не контроль." }, category: "fuehrung", relatedTerms: ["authentische-fuehrung", "empowerment", "fuehrungsstil"], relatedServices: ["coaching", "corporate", "keynotes"] },
  { slug: "empowerment", term: { de: "Empowerment", en: "Empowerment", ru: "Расширение полномочий" }, definition: { de: "Empowerment bezeichnet die Befähigung und Ermächtigung von Mitarbeitern, eigenverantwortlich zu handeln. Es schafft Innovation, Engagement und eine Kultur des Vertrauens innerhalb von Organisationen.", en: "Empowerment refers to enabling and empowering employees to act independently. It creates innovation, engagement, and a culture of trust within organizations.", ru: "Расширение полномочий — наделение сотрудников правом действовать самостоятельно. Оно создаёт инновации, вовлечённость и культуру доверия в организациях." }, category: "fuehrung", relatedTerms: ["bewusste-fuehrung", "servant-leadership", "agilitat"], relatedServices: ["corporate"] },
  { slug: "fuehrungsstil", term: { de: "Führungsstil", en: "Leadership Style", ru: "Стиль лидерства" }, definition: { de: "Der Führungsstil beschreibt die charakteristische Art, wie eine Führungskraft ihre Rolle ausfüllt. Bewusste Führungskräfte wählen ihren Stil situativ und reflektiert statt aus Gewohnheit oder Unsicherheit.", en: "Leadership style describes the characteristic way a leader fulfills their role. Conscious leaders choose their style situationally and reflectively rather than out of habit or insecurity.", ru: "Стиль лидерства описывает характерный способ, которым руководитель выполняет свою роль. Осознанные лидеры выбирают стиль ситуативно и рефлективно, а не по привычке." }, category: "fuehrung", relatedTerms: ["bewusste-fuehrung", "situative-fuehrung", "servant-leadership"], relatedServices: ["coaching", "corporate"] },
  { slug: "leadership", term: { de: "Leadership", en: "Leadership", ru: "Лидерство" }, definition: { de: "Leadership geht über Management hinaus — es ist die Fähigkeit, Menschen zu inspirieren, eine gemeinsame Vision zu verfolgen. Echtes Leadership entsteht aus innerer Klarheit und der Bereitschaft, Verantwortung zu tragen.", en: "Leadership goes beyond management — it is the ability to inspire people to pursue a shared vision. True leadership arises from inner clarity and the willingness to bear responsibility.", ru: "Лидерство выходит за рамки менеджмента — это способность вдохновлять людей следовать общему видению. Настоящее лидерство рождается из внутренней ясности и готовности нести ответственность." }, category: "fuehrung", relatedTerms: ["bewusste-fuehrung", "visionaere-fuehrung", "authentische-fuehrung"], relatedServices: ["coaching", "keynotes"] },
  { slug: "servant-leadership", term: { de: "Servant Leadership", en: "Servant Leadership", ru: "Служащее лидерство" }, definition: { de: "Servant Leadership stellt die Bedürfnisse der Mitarbeiter und der Organisation vor die eigenen Interessen der Führungskraft. Dieser Ansatz fördert Vertrauen, Autonomie und eine nachhaltige Leistungskultur.", en: "Servant Leadership puts the needs of employees and the organization before the leader's own interests. This approach fosters trust, autonomy, and a sustainable performance culture.", ru: "Служащее лидерство ставит потребности сотрудников и организации выше личных интересов руководителя. Этот подход способствует доверию, автономии и устойчивой культуре результативности." }, category: "fuehrung", relatedTerms: ["empowerment", "bewusste-fuehrung", "authentische-fuehrung"], relatedServices: ["corporate", "coaching"] },
  { slug: "situative-fuehrung", term: { de: "Situative Führung", en: "Situational Leadership", ru: "Ситуативное лидерство" }, definition: { de: "Situative Führung passt den Führungsstil an die Reife und Kompetenz der Mitarbeiter sowie an die jeweilige Situation an. Es erfordert hohe Bewusstheit und die Fähigkeit, flexibel zwischen Stilen zu wechseln.", en: "Situational leadership adapts the leadership style to the maturity and competence of employees and to the specific situation. It requires high awareness and the ability to flexibly switch between styles.", ru: "Ситуативное лидерство адаптирует стиль руководства к зрелости и компетенции сотрудников и конкретной ситуации. Оно требует высокой осознанности и способности гибко переключаться между стилями." }, category: "fuehrung", relatedTerms: ["fuehrungsstil", "bewusste-fuehrung", "empowerment"], relatedServices: ["corporate"] },
  { slug: "visionaere-fuehrung", term: { de: "Visionäre Führung", en: "Visionary Leadership", ru: "Визионерское лидерство" }, definition: { de: "Visionäre Führung inspiriert durch ein klares Bild der Zukunft und die Fähigkeit, andere für diese Vision zu begeistern. Sie verbindet strategisches Denken mit emotionaler Intelligenz und innerem Feuer.", en: "Visionary leadership inspires through a clear picture of the future and the ability to enthuse others for this vision. It combines strategic thinking with emotional intelligence and inner fire.", ru: "Визионерское лидерство вдохновляет ясной картиной будущего и способностью увлечь других этим видением. Оно сочетает стратегическое мышление с эмоциональным интеллектом и внутренним огнём." }, category: "fuehrung", relatedTerms: ["leadership", "bewusste-fuehrung", "innere-klarheit"], relatedServices: ["keynotes", "coaching"] },
  { slug: "executive-coaching", term: { de: "Executive Coaching", en: "Executive Coaching", ru: "Коучинг руководителей" }, definition: { de: "Executive Coaching ist eine professionelle Begleitung für Führungskräfte auf höchster Ebene. Es adressiert komplexe Herausforderungen wie strategische Entscheidungen, Stakeholder-Management und persönliche Weiterentwicklung in Verantwortungspositionen.", en: "Executive coaching is professional accompaniment for leaders at the highest level. It addresses complex challenges such as strategic decisions, stakeholder management, and personal development in positions of responsibility.", ru: "Коучинг руководителей — профессиональное сопровождение лидеров на высшем уровне. Он адресует сложные вызовы: стратегические решения, управление стейкхолдерами и личное развитие на ответственных позициях." }, category: "coaching", relatedTerms: ["einzelcoaching", "mentoring", "sparring"], relatedServices: ["coaching"] },
  { slug: "einzelcoaching", term: { de: "Einzelcoaching", en: "Individual Coaching", ru: "Индивидуальный коучинг" }, definition: { de: "Einzelcoaching ist die intensivste Form der persönlichen Begleitung. In vertraulichem Rahmen arbeiten Coach und Klient an individuellen Zielen, Herausforderungen und persönlichem Wachstum.", en: "Individual coaching is the most intensive form of personal accompaniment. In a confidential setting, coach and client work on individual goals, challenges, and personal growth.", ru: "Индивидуальный коучинг — наиболее интенсивная форма персонального сопровождения. В конфиденциальной обстановке коуч и клиент работают над целями, вызовами и личным ростом." }, category: "coaching", relatedTerms: ["executive-coaching", "mentoring", "systemisches-coaching"], relatedServices: ["coaching"] },
  { slug: "gruppencoaching", term: { de: "Gruppencoaching", en: "Group Coaching", ru: "Групповой коучинг" }, definition: { de: "Gruppencoaching nutzt die Dynamik und Diversität einer Gruppe, um individuelle und kollektive Lernprozesse zu fördern. Teilnehmer profitieren von verschiedenen Perspektiven und gegenseitiger Unterstützung.", en: "Group coaching uses the dynamics and diversity of a group to promote individual and collective learning processes. Participants benefit from different perspectives and mutual support.", ru: "Групповой коучинг использует динамику и разнообразие группы для развития индивидуальных и коллективных процессов обучения. Участники выигрывают от разных перспектив и взаимной поддержки." }, category: "coaching", relatedTerms: ["team-coaching", "einzelcoaching", "workshop"], relatedServices: ["seminare", "corporate"] },
  { slug: "mentoring", term: { de: "Mentoring", en: "Mentoring", ru: "Менторинг" }, definition: { de: "Mentoring ist eine Beziehung, in der ein erfahrener Mentor sein Wissen, seine Erfahrung und seine Netzwerke mit dem Mentee teilt. Es verbindet persönliche Entwicklung mit praktischer Lebens- und Berufserfahrung.", en: "Mentoring is a relationship in which an experienced mentor shares their knowledge, experience, and networks with the mentee. It combines personal development with practical life and professional experience.", ru: "Менторинг — отношения, в которых опытный ментор делится знаниями, опытом и связями с менти. Он сочетает личное развитие с практическим жизненным и профессиональным опытом." }, category: "coaching", relatedTerms: ["executive-coaching", "sparring", "einzelcoaching"], relatedServices: ["coaching"] },
  { slug: "systemisches-coaching", term: { de: "Systemisches Coaching", en: "Systemic Coaching", ru: "Системный коучинг" }, definition: { de: "Systemisches Coaching betrachtet den Menschen im Kontext seiner Beziehungen und Systeme. Es erkennt, dass Veränderung in einem Bereich Auswirkungen auf das gesamte System hat, und nutzt diese Erkenntnis für nachhaltige Transformation.", en: "Systemic coaching views the person in the context of their relationships and systems. It recognizes that change in one area impacts the entire system and uses this insight for sustainable transformation.", ru: "Системный коучинг рассматривает человека в контексте его отношений и систем. Он признаёт, что изменение в одной области влияет на всю систему, и использует это для устойчивой трансформации." }, category: "coaching", relatedTerms: ["einzelcoaching", "team-coaching", "organisationsentwicklung"], relatedServices: ["coaching", "corporate"] },
  { slug: "team-coaching", term: { de: "Team Coaching", en: "Team Coaching", ru: "Командный коучинг" }, definition: { de: "Team Coaching entwickelt die Leistungsfähigkeit und Zusammenarbeit eines Teams als Ganzes. Es adressiert Gruppendynamiken, Kommunikationsmuster und die gemeinsame Ausrichtung auf Ziele.", en: "Team coaching develops the performance and collaboration of a team as a whole. It addresses group dynamics, communication patterns, and shared alignment toward goals.", ru: "Командный коучинг развивает эффективность и сотрудничество команды как целого. Он работает с групповой динамикой, паттернами коммуникации и общей направленностью на цели." }, category: "coaching", relatedTerms: ["gruppencoaching", "systemisches-coaching", "empowerment"], relatedServices: ["corporate"] },
  { slug: "supervision", term: { de: "Supervision", en: "Supervision", ru: "Супервизия" }, definition: { de: "Supervision ist die professionelle Reflexion beruflichen Handelns. Sie hilft Fachkräften und Führungskräften, ihre Arbeit zu reflektieren, blinde Flecken zu erkennen und die Qualität ihrer Beziehungsarbeit zu verbessern.", en: "Supervision is the professional reflection of professional action. It helps professionals and leaders reflect on their work, recognize blind spots, and improve the quality of their relational work.", ru: "Супервизия — профессиональная рефлексия деятельности. Она помогает специалистам и руководителям осмыслять работу, распознавать слепые зоны и улучшать качество межличностного взаимодействия." }, category: "coaching", relatedTerms: ["reflexion", "sparring", "feedback"], relatedServices: ["coaching"] },
  { slug: "sparring", term: { de: "Sparring", en: "Sparring", ru: "Спарринг" }, definition: { de: "Sparring ist ein Dialog auf Augenhöhe, bei dem Ideen, Strategien und Entscheidungen kritisch hinterfragt werden. Es bietet Führungskräften einen geschützten Raum, um Gedanken zu schärfen und neue Perspektiven zu gewinnen.", en: "Sparring is a dialogue at eye level where ideas, strategies, and decisions are critically questioned. It provides leaders with a safe space to sharpen thoughts and gain new perspectives.", ru: "Спарринг — диалог на равных, где идеи, стратегии и решения критически проверяются. Он предоставляет руководителям безопасное пространство для заточки мыслей и обретения новых перспектив." }, category: "coaching", relatedTerms: ["mentoring", "executive-coaching", "reflexion"], relatedServices: ["coaching"] },
  { slug: "persoenliche-transformation", term: { de: "Persönliche Transformation", en: "Personal Transformation", ru: "Личная трансформация" }, definition: { de: "Persönliche Transformation ist ein tiefgreifender Wandel in Wahrnehmung, Denken und Handeln. Sie geht über oberflächliche Verhaltensänderung hinaus und berührt die Kernidentität eines Menschen.", en: "Personal transformation is a profound shift in perception, thinking, and action. It goes beyond superficial behavioral change and touches a person's core identity.", ru: "Личная трансформация — глубокий сдвиг в восприятии, мышлении и действиях. Она выходит за рамки поверхностных изменений поведения и затрагивает ядро идентичности." }, category: "transformation", relatedTerms: ["veraenderungsprozess", "wachstum", "bewusstseinsentwicklung"], relatedServices: ["transformation", "coaching"] },
  { slug: "resilienz", term: { de: "Resilienz", en: "Resilience", ru: "Стойкость" }, definition: { de: "Resilienz ist die Fähigkeit, mit Stress, Krisen und Rückschlägen konstruktiv umzugehen und gestärkt daraus hervorzugehen. Sie basiert auf Bewusstheit, Flexibilität und einem stabilen inneren Fundament.", en: "Resilience is the ability to constructively deal with stress, crises, and setbacks and emerge stronger. It is based on awareness, flexibility, and a stable inner foundation.", ru: "Стойкость — способность конструктивно справляться со стрессом, кризисами и неудачами, выходя из них сильнее. Она основана на осознанности, гибкости и стабильном внутреннем фундаменте." }, category: "transformation", relatedTerms: ["stress", "selbstwirksamkeit", "innere-klarheit"], relatedServices: ["coaching", "seminare"] },
  { slug: "veraenderungsprozess", term: { de: "Veränderungsprozess", en: "Change Process", ru: "Процесс изменений" }, definition: { de: "Ein Veränderungsprozess umfasst alle Phasen von der Erkenntnis der Notwendigkeit bis zur Integration neuer Verhaltensweisen. Bewusste Begleitung macht den Unterschied zwischen kurzfristiger Anpassung und nachhaltiger Transformation.", en: "A change process encompasses all phases from recognizing the necessity to integrating new behaviors. Conscious accompaniment makes the difference between short-term adjustment and sustainable transformation.", ru: "Процесс изменений охватывает все этапы от осознания необходимости до интеграции нового поведения. Осознанное сопровождение отличает краткосрочную адаптацию от устойчивой трансформации." }, category: "transformation", relatedTerms: ["persoenliche-transformation", "wachstum", "gewohnheitsaenderung"], relatedServices: ["coaching", "transformation"] },
  { slug: "wachstum", term: { de: "Wachstum", en: "Growth", ru: "Рост" }, definition: { de: "Persönliches Wachstum ist die kontinuierliche Entwicklung von Fähigkeiten, Bewusstsein und Charakter. Es erfordert die Bereitschaft, die eigene Komfortzone zu verlassen und sich neuen Herausforderungen zu stellen.", en: "Personal growth is the continuous development of skills, awareness, and character. It requires the willingness to leave one's comfort zone and face new challenges.", ru: "Личный рост — непрерывное развитие навыков, осознанности и характера. Он требует готовности покинуть зону комфорта и принять новые вызовы." }, category: "transformation", relatedTerms: ["persoenliche-transformation", "selbstoptimierung", "bewusstseinsentwicklung"], relatedServices: ["coaching", "seminare"] },
  { slug: "selbstoptimierung", term: { de: "Selbstoptimierung", en: "Self-Optimization", ru: "Самооптимизация" }, definition: { de: "Selbstoptimierung beschreibt den bewussten Prozess, die eigene Leistungsfähigkeit und Lebensqualität zu steigern. Im Kontext bewusster Führung geht es nicht um Perfektionismus, sondern um authentische Entfaltung des eigenen Potenzials.", en: "Self-optimization describes the conscious process of improving one's performance capacity and quality of life. In the context of conscious leadership, it is not about perfectionism but about authentic unfolding of one's potential.", ru: "Самооптимизация — осознанный процесс повышения работоспособности и качества жизни. В контексте осознанного лидерства речь не о перфекционизме, а об аутентичном раскрытии потенциала." }, category: "transformation", relatedTerms: ["wachstum", "persoenliche-transformation", "selbstwirksamkeit"], relatedServices: ["coaching"] },
  { slug: "identitaetsarbeit", term: { de: "Identitätsarbeit", en: "Identity Work", ru: "Работа с идентичностью" }, definition: { de: "Identitätsarbeit befasst sich mit der bewussten Auseinandersetzung mit dem eigenen Selbstbild, Rollen und Prägungen. Sie ermöglicht tiefgreifende Veränderung, indem sie an der Wurzel ansetzt statt nur an Symptomen.", en: "Identity work involves the conscious examination of one's self-image, roles, and conditioning. It enables profound change by addressing the root rather than just symptoms.", ru: "Работа с идентичностью — осознанное исследование самовосприятия, ролей и обусловленностей. Она позволяет глубокие изменения, работая с корнем, а не только с симптомами." }, category: "transformation", relatedTerms: ["persoenliche-transformation", "selbstbewusstsein", "selbsterkenntnis"], relatedServices: ["coaching"] },
  { slug: "gewohnheitsaenderung", term: { de: "Gewohnheitsänderung", en: "Habit Change", ru: "Изменение привычек" }, definition: { de: "Gewohnheitsänderung erfordert mehr als Willenskraft — sie braucht Bewusstheit über die zugrundeliegenden Auslöser und Belohnungsmuster. Nachhaltige Gewohnheitsänderung entsteht durch Verständnis, nicht durch Zwang.", en: "Habit change requires more than willpower — it needs awareness of the underlying triggers and reward patterns. Sustainable habit change comes through understanding, not through force.", ru: "Изменение привычек требует большего, чем сила воли — осознания скрытых триггеров и паттернов вознаграждения. Устойчивое изменение привычек приходит через понимание, а не через принуждение." }, category: "transformation", relatedTerms: ["veraenderungsprozess", "selbstoptimierung", "prokrastination"], relatedServices: ["coaching"] },
  { slug: "neuausrichtung", term: { de: "Neuausrichtung", en: "Realignment", ru: "Переориентация" }, definition: { de: "Neuausrichtung ist der bewusste Prozess, Lebens- oder Karriereziele neu zu definieren und den eigenen Kurs zu korrigieren. Sie entsteht oft in Umbruchphasen und erfordert Mut, Klarheit und einen vertrauenswürdigen Sparring-Partner.", en: "Realignment is the conscious process of redefining life or career goals and correcting one's course. It often arises during transition phases and requires courage, clarity, and a trustworthy sparring partner.", ru: "Переориентация — осознанный процесс переопределения целей и корректировки курса. Часто возникает в переходные периоды и требует мужества, ясности и доверенного партнёра для спарринга." }, category: "transformation", relatedTerms: ["persoenliche-transformation", "innere-klarheit", "veraenderungsprozess"], relatedServices: ["coaching", "transformation"] },
  { slug: "agilitat", term: { de: "Agilität", en: "Agility", ru: "Гибкость" }, definition: { de: "Agilität beschreibt die Fähigkeit von Organisationen und Individuen, schnell und flexibel auf Veränderungen zu reagieren. Wahre Agilität basiert auf bewusster Führung und einer Kultur des Vertrauens.", en: "Agility describes the ability of organizations and individuals to react quickly and flexibly to changes. True agility is based on conscious leadership and a culture of trust.", ru: "Гибкость описывает способность организаций и людей быстро и гибко реагировать на изменения. Истинная гибкость основана на осознанном лидерстве и культуре доверия." }, category: "business", relatedTerms: ["new-work", "organisationsentwicklung", "unternehmenskultur"], relatedServices: ["corporate"] },
  { slug: "corporate-culture", term: { de: "Corporate Culture", en: "Corporate Culture", ru: "Корпоративная культура" }, definition: { de: "Corporate Culture umfasst die gemeinsamen Werte, Normen und Verhaltensweisen in einem Unternehmen. Eine bewusste Unternehmenskultur entsteht nicht durch Leitbilder an der Wand, sondern durch gelebte Führung.", en: "Corporate culture encompasses the shared values, norms, and behaviors in a company. A conscious corporate culture does not emerge from mission statements on the wall but through lived leadership.", ru: "Корпоративная культура охватывает общие ценности, нормы и модели поведения в компании. Осознанная корпоративная культура возникает не из лозунгов на стене, а через живое лидерство." }, category: "business", relatedTerms: ["unternehmenskultur", "agilitat", "organisationsentwicklung"], relatedServices: ["corporate"] },
  { slug: "new-work", term: { de: "New Work", en: "New Work", ru: "Новая работа" }, definition: { de: "New Work beschreibt neue Arbeitsformen, die auf Selbstbestimmung, Sinnhaftigkeit und Gemeinschaft basieren. Bewusste Führung ist der Schlüssel, damit New Work nicht nur ein Schlagwort bleibt.", en: "New Work describes new forms of work based on self-determination, meaningfulness, and community. Conscious leadership is the key to ensuring New Work does not remain just a buzzword.", ru: "New Work описывает новые формы работы, основанные на самоопределении, осмысленности и общности. Осознанное лидерство — ключ к тому, чтобы New Work не осталась лишь модным словом." }, category: "business", relatedTerms: ["agilitat", "unternehmenskultur", "empowerment"], relatedServices: ["corporate", "keynotes"] },
  { slug: "organisationsentwicklung", term: { de: "Organisationsentwicklung", en: "Organizational Development", ru: "Организационное развитие" }, definition: { de: "Organisationsentwicklung ist ein geplanter, systematischer Prozess zur Verbesserung der Leistungsfähigkeit und Gesundheit einer Organisation. Sie beginnt immer bei den Führungskräften und ihrer Bewusstheit.", en: "Organizational development is a planned, systematic process for improving the performance and health of an organization. It always begins with leaders and their awareness.", ru: "Организационное развитие — планомерный процесс улучшения эффективности и здоровья организации. Оно всегда начинается с руководителей и их осознанности." }, category: "business", relatedTerms: ["corporate-culture", "agilitat", "unternehmenskultur"], relatedServices: ["corporate"] },
  { slug: "unternehmenskultur", term: { de: "Unternehmenskultur", en: "Company Culture", ru: "Культура компании" }, definition: { de: "Unternehmenskultur ist das unsichtbare Betriebssystem einer Organisation — sie bestimmt, wie Entscheidungen getroffen, Konflikte gelöst und Innovation gelebt wird. Kulturwandel beginnt bei bewusster Führung.", en: "Company culture is the invisible operating system of an organization — it determines how decisions are made, conflicts resolved, and innovation practiced. Cultural change begins with conscious leadership.", ru: "Культура компании — невидимая операционная система организации. Она определяет, как принимаются решения, разрешаются конфликты и практикуются инновации. Культурные изменения начинаются с осознанного лидерства." }, category: "business", relatedTerms: ["corporate-culture", "organisationsentwicklung", "bewusste-fuehrung"], relatedServices: ["corporate"] },
  { slug: "innovation", term: { de: "Innovation", en: "Innovation", ru: "Инновация" }, definition: { de: "Innovation entsteht nicht durch Prozesse allein, sondern durch ein Klima der psychologischen Sicherheit und bewussten Kreativität. Führungskräfte, die Raum für Neues schaffen, fördern echte Innovation.", en: "Innovation does not come from processes alone but from a climate of psychological safety and conscious creativity. Leaders who create space for the new foster genuine innovation.", ru: "Инновация возникает не только из процессов, а из климата психологической безопасности и осознанной креативности. Руководители, создающие пространство для нового, способствуют настоящим инновациям." }, category: "business", relatedTerms: ["agilitat", "new-work", "unternehmenskultur"], relatedServices: ["corporate", "keynotes"] },
  { slug: "nachhaltigkeit", term: { de: "Nachhaltigkeit", en: "Sustainability", ru: "Устойчивость" }, definition: { de: "Nachhaltigkeit in der Führung bedeutet, langfristiges Denken und Handeln in den Mittelpunkt zu stellen. Nachhaltige Führung schafft Wert für alle Stakeholder, nicht nur kurzfristigen Profit.", en: "Sustainability in leadership means placing long-term thinking and action at the center. Sustainable leadership creates value for all stakeholders, not just short-term profit.", ru: "Устойчивость в лидерстве означает фокус на долгосрочном мышлении и действиях. Устойчивое лидерство создаёт ценность для всех заинтересованных сторон, а не только краткосрочную прибыль." }, category: "business", relatedTerms: ["verantwortung", "ethik", "bewusste-fuehrung"], relatedServices: ["corporate"] },
  { slug: "employer-branding", term: { de: "Employer Branding", en: "Employer Branding", ru: "Бренд работодателя" }, definition: { de: "Employer Branding ist die strategische Positionierung als attraktiver Arbeitgeber. Authentisches Employer Branding beginnt mit einer gelebten, bewussten Unternehmenskultur, die Talente natürlich anzieht.", en: "Employer branding is the strategic positioning as an attractive employer. Authentic employer branding begins with a lived, conscious corporate culture that naturally attracts talent.", ru: "Бренд работодателя — стратегическое позиционирование как привлекательного работодателя. Аутентичный бренд начинается с живой, осознанной корпоративной культуры, естественно привлекающей таланты." }, category: "business", relatedTerms: ["unternehmenskultur", "corporate-culture", "new-work"], relatedServices: ["corporate"] },
  { slug: "assessment", term: { de: "Assessment", en: "Assessment", ru: "Оценка" }, definition: { de: "Assessment-Verfahren erfassen den Entwicklungsstand, Potenziale und Muster einer Person oder eines Teams. Sie bilden die Grundlage für gezielte Coaching- und Entwicklungsmaßnahmen.", en: "Assessment procedures capture the development level, potentials, and patterns of a person or team. They form the basis for targeted coaching and development measures.", ru: "Процедуры оценки фиксируют уровень развития, потенциалы и паттерны человека или команды. Они составляют основу для целенаправленного коучинга и развития." }, category: "methodik", relatedTerms: ["feedback", "reflexion", "einzelcoaching"], relatedServices: ["coaching", "corporate"] },
  { slug: "feedback", term: { de: "Feedback", en: "Feedback", ru: "Обратная связь" }, definition: { de: "Feedback ist ein Werkzeug für Wachstum und Klarheit. Konstruktives Feedback zu geben und anzunehmen erfordert Bewusstheit, Mut und die Bereitschaft, die eigene Wahrnehmung zu hinterfragen.", en: "Feedback is a tool for growth and clarity. Giving and receiving constructive feedback requires awareness, courage, and the willingness to question one's own perception.", ru: "Обратная связь — инструмент роста и ясности. Давать и принимать конструктивную обратную связь требует осознанности, мужества и готовности ставить под вопрос собственное восприятие." }, category: "methodik", relatedTerms: ["assessment", "reflexion", "supervision"], relatedServices: ["coaching", "corporate"] },
  { slug: "journaling", term: { de: "Journaling", en: "Journaling", ru: "Ведение дневника" }, definition: { de: "Journaling ist die Praxis des strukturierten Schreibens zur Selbstreflexion. Es macht unbewusste Gedanken und Muster sichtbar und unterstützt die Integration von Coaching-Erkenntnissen im Alltag.", en: "Journaling is the practice of structured writing for self-reflection. It makes unconscious thoughts and patterns visible and supports the integration of coaching insights into daily life.", ru: "Ведение дневника — практика структурированного письма для саморефлексии. Оно делает видимыми неосознанные мысли и паттерны и помогает интегрировать инсайты коучинга в повседневную жизнь." }, category: "methodik", relatedTerms: ["reflexion", "selbstbewusstsein", "achtsamkeit"], relatedServices: ["coaching", "resources"] },
  { slug: "reflexion", term: { de: "Reflexion", en: "Reflection", ru: "Рефлексия" }, definition: { de: "Reflexion ist die bewusste Rückschau auf Erfahrungen, Handlungen und deren Auswirkungen. Regelmäßige Reflexion ist das Fundament persönlichen Wachstums und bewusster Führung.", en: "Reflection is the conscious review of experiences, actions, and their effects. Regular reflection is the foundation of personal growth and conscious leadership.", ru: "Рефлексия — осознанный анализ опыта, действий и их последствий. Регулярная рефлексия — фундамент личного роста и осознанного лидерства." }, category: "methodik", relatedTerms: ["journaling", "supervision", "selbstbewusstsein"], relatedServices: ["coaching"] },
  { slug: "retreat", term: { de: "Retreat", en: "Retreat", ru: "Ретрит" }, definition: { de: "Ein Retreat ist ein mehrtägiger Rückzug aus dem Alltag für intensive persönliche Arbeit. In der Stille und Konzentration eines Retreats entstehen tiefe Einsichten und nachhaltige Transformation.", en: "A retreat is a multi-day withdrawal from daily life for intensive personal work. In the stillness and concentration of a retreat, deep insights and sustainable transformation emerge.", ru: "Ретрит — многодневный уход от повседневности для интенсивной личной работы. В тишине и концентрации ретрита рождаются глубокие инсайты и устойчивая трансформация." }, category: "methodik", relatedTerms: ["meditation", "achtsamkeit", "persoenliche-transformation"], relatedServices: ["seminare"] },
  { slug: "visualisierung", term: { de: "Visualisierung", en: "Visualization", ru: "Визуализация" }, definition: { de: "Visualisierung ist eine mentale Technik, bei der gewünschte Ergebnisse bildhaft vorgestellt werden. In Coaching und Führung unterstützt sie die Klärung von Zielen und die Mobilisierung innerer Ressourcen.", en: "Visualization is a mental technique where desired outcomes are pictured mentally. In coaching and leadership, it supports goal clarification and the mobilization of inner resources.", ru: "Визуализация — ментальная техника, при которой желаемые результаты представляются в образах. В коучинге и лидерстве она помогает прояснить цели и мобилизовать внутренние ресурсы." }, category: "methodik", relatedTerms: ["meditation", "reflexion", "innere-klarheit"], relatedServices: ["coaching"] },
  { slug: "workshop", term: { de: "Workshop", en: "Workshop", ru: "Воркшоп" }, definition: { de: "Ein Workshop ist ein interaktives Format, in dem Teilnehmer aktiv an einem Thema arbeiten. Workshops verbinden Wissensvermittlung mit praktischer Anwendung und Gruppenerfahrung.", en: "A workshop is an interactive format where participants actively work on a topic. Workshops combine knowledge transfer with practical application and group experience.", ru: "Воркшоп — интерактивный формат, где участники активно работают над темой. Воркшопы сочетают передачу знаний с практическим применением и групповым опытом." }, category: "methodik", relatedTerms: ["retreat", "gruppencoaching", "facilitation"], relatedServices: ["seminare"] },
  { slug: "facilitation", term: { de: "Facilitation", en: "Facilitation", ru: "Фасилитация" }, definition: { de: "Facilitation ist die Kunst, Gruppenprozesse so zu gestalten, dass alle Teilnehmer ihr Bestes einbringen können. Ein guter Facilitator schafft den Rahmen, ohne den Inhalt zu bestimmen.", en: "Facilitation is the art of designing group processes so that all participants can contribute their best. A good facilitator creates the framework without determining the content.", ru: "Фасилитация — искусство организации групповых процессов так, чтобы каждый участник мог внести лучшее. Хороший фасилитатор создаёт рамку, не определяя содержание." }, category: "methodik", relatedTerms: ["workshop", "gruppencoaching", "team-coaching"], relatedServices: ["corporate", "seminare"] },
  { slug: "burnout", term: { de: "Burnout", en: "Burnout", ru: "Выгорание" }, definition: { de: "Burnout ist ein Zustand emotionaler, körperlicher und geistiger Erschöpfung durch chronischen Stress. Bewusste Führung und Selbstkenntnis sind der beste Schutz — Prävention beginnt mit Bewusstheit.", en: "Burnout is a state of emotional, physical, and mental exhaustion from chronic stress. Conscious leadership and self-knowledge are the best protection — prevention begins with awareness.", ru: "Выгорание — состояние эмоционального, физического и ментального истощения от хронического стресса. Осознанное лидерство и самопознание — лучшая защита. Профилактика начинается с осознанности." }, category: "psychologie", relatedTerms: ["stress", "resilienz", "selbstwirksamkeit"], relatedServices: ["coaching"] },
  { slug: "emotionale-intelligenz", term: { de: "Emotionale Intelligenz", en: "Emotional Intelligence", ru: "Эмоциональный интеллект" }, definition: { de: "Emotionale Intelligenz ist die Fähigkeit, eigene und fremde Emotionen wahrzunehmen, zu verstehen und konstruktiv zu nutzen. Sie ist eine der wichtigsten Führungskompetenzen und kann gezielt entwickelt werden.", en: "Emotional intelligence is the ability to perceive, understand, and constructively use one's own and others' emotions. It is one of the most important leadership competencies and can be specifically developed.", ru: "Эмоциональный интеллект — способность воспринимать, понимать и конструктивно использовать собственные и чужие эмоции. Это одна из важнейших лидерских компетенций, которая целенаправленно развивается." }, category: "psychologie", relatedTerms: ["selbstbewusstsein", "empathie", "bewusste-fuehrung"], relatedServices: ["coaching", "corporate"] },
  { slug: "flow", term: { de: "Flow", en: "Flow", ru: "Поток" }, definition: { de: "Flow ist der Zustand vollständiger Vertiefung in eine Tätigkeit, in dem Zeit und Selbstbewusstsein in den Hintergrund treten. Bewusste Führungskräfte schaffen Bedingungen, die Flow für sich und ihre Teams fördern.", en: "Flow is the state of complete immersion in an activity where time and self-consciousness fade into the background. Conscious leaders create conditions that promote flow for themselves and their teams.", ru: "Поток — состояние полного погружения в деятельность, когда время и самосознание уходят на второй план. Осознанные лидеры создают условия, способствующие потоку для себя и своих команд." }, category: "psychologie", relatedTerms: ["praesenz", "motivation", "achtsamkeit"], relatedServices: ["coaching"] },
  { slug: "intuition", term: { de: "Intuition", en: "Intuition", ru: "Интуиция" }, definition: { de: "Intuition ist die Fähigkeit, ohne bewusste Analyse zu richtigen Einschätzungen zu gelangen. In der bewussten Führung wird Intuition als wertvolle Ergänzung zu rationaler Analyse kultiviert.", en: "Intuition is the ability to arrive at correct assessments without conscious analysis. In conscious leadership, intuition is cultivated as a valuable complement to rational analysis.", ru: "Интуиция — способность приходить к верным оценкам без сознательного анализа. В осознанном лидерстве интуиция культивируется как ценное дополнение к рациональному анализу." }, category: "psychologie", relatedTerms: ["innere-klarheit", "bewusstsein", "entscheidungsstaerke"], relatedServices: ["coaching"] },
  { slug: "motivation", term: { de: "Motivation", en: "Motivation", ru: "Мотивация" }, definition: { de: "Intrinsische Motivation entsteht aus Sinn, Autonomie und Meisterschaft — nicht aus externen Anreizen. Bewusste Führungskräfte verstehen die Motivationsquellen ihrer Mitarbeiter und schaffen entsprechende Rahmenbedingungen.", en: "Intrinsic motivation arises from purpose, autonomy, and mastery — not from external incentives. Conscious leaders understand their employees' motivation sources and create appropriate conditions.", ru: "Внутренняя мотивация рождается из смысла, автономии и мастерства — не из внешних стимулов. Осознанные лидеры понимают источники мотивации сотрудников и создают соответствующие условия." }, category: "psychologie", relatedTerms: ["flow", "sinn", "empowerment"], relatedServices: ["corporate", "coaching"] },
  { slug: "selbstwirksamkeit", term: { de: "Selbstwirksamkeit", en: "Self-Efficacy", ru: "Самоэффективность" }, definition: { de: "Selbstwirksamkeit ist die Überzeugung, durch eigenes Handeln gewünschte Ergebnisse erzielen zu können. Sie ist ein zentraler Faktor für Resilienz, Motivation und den Mut, neue Wege zu gehen.", en: "Self-efficacy is the belief that one can achieve desired results through one's own actions. It is a central factor for resilience, motivation, and the courage to take new paths.", ru: "Самоэффективность — убеждённость в способности достигать желаемых результатов собственными действиями. Это центральный фактор стойкости, мотивации и мужества идти новыми путями." }, category: "psychologie", relatedTerms: ["resilienz", "motivation", "selbstbewusstsein"], relatedServices: ["coaching"] },
  { slug: "stress", term: { de: "Stress", en: "Stress", ru: "Стресс" }, definition: { de: "Stress ist die Reaktion auf Anforderungen, die als herausfordernd oder bedrohlich empfunden werden. Bewusster Umgang mit Stress bedeutet, die eigenen Stressmuster zu erkennen und konstruktive Bewältigungsstrategien zu entwickeln.", en: "Stress is the response to demands perceived as challenging or threatening. Conscious stress management means recognizing one's own stress patterns and developing constructive coping strategies.", ru: "Стресс — реакция на требования, воспринимаемые как вызов или угрозу. Осознанное управление стрессом означает распознавание собственных стресс-паттернов и развитие конструктивных стратегий преодоления." }, category: "psychologie", relatedTerms: ["burnout", "resilienz", "achtsamkeit"], relatedServices: ["coaching"] },
  { slug: "prokrastination", term: { de: "Prokrastination", en: "Procrastination", ru: "Прокрастинация" }, definition: { de: "Prokrastination ist das chronische Aufschieben wichtiger Aufgaben trotz besseren Wissens. Hinter ihr verbergen sich oft Ängste, Perfektionismus oder mangelnde Klarheit über Prioritäten — alles Themen, die im Coaching adressiert werden.", en: "Procrastination is the chronic postponement of important tasks despite better knowledge. Behind it often lie fears, perfectionism, or lack of clarity about priorities — all topics addressed in coaching.", ru: "Прокрастинация — хроническое откладывание важных задач вопреки лучшему знанию. За ней часто скрываются страхи, перфекционизм или неясность приоритетов — всё это темы для проработки в коучинге." }, category: "psychologie", relatedTerms: ["motivation", "gewohnheitsaenderung", "innere-klarheit"], relatedServices: ["coaching"] },
  { slug: "autonomie", term: { de: "Autonomie", en: "Autonomy", ru: "Автономия" }, definition: { de: "Autonomie ist die Fähigkeit zur Selbstbestimmung und eigenverantwortlichem Handeln. In der bewussten Führung bedeutet Autonomie, sowohl sich selbst als auch anderen den Raum für eigenständige Entscheidungen zu geben.", en: "Autonomy is the ability for self-determination and responsible action. In conscious leadership, autonomy means giving both oneself and others the space for independent decisions.", ru: "Автономия — способность к самоопределению и ответственному действию. В осознанном лидерстве автономия означает предоставление себе и другим пространства для самостоятельных решений." }, category: "philosophie", relatedTerms: ["verantwortung", "empowerment", "werte"], relatedServices: ["coaching"] },
  { slug: "ethik", term: { de: "Ethik", en: "Ethics", ru: "Этика" }, definition: { de: "Ethik in der Führung bedeutet, Entscheidungen nicht nur nach Effizienz, sondern nach moralischen Grundsätzen zu treffen. Ethische Führung schafft Vertrauen und langfristigen Wert für alle Beteiligten.", en: "Ethics in leadership means making decisions not only based on efficiency but on moral principles. Ethical leadership creates trust and long-term value for all stakeholders.", ru: "Этика в лидерстве означает принятие решений не только по критерию эффективности, но и на основе моральных принципов. Этичное лидерство создаёт доверие и долгосрочную ценность для всех." }, category: "philosophie", relatedTerms: ["integritaet", "verantwortung", "werte"], relatedServices: ["corporate", "keynotes"] },
  { slug: "integritaet", term: { de: "Integrität", en: "Integrity", ru: "Целостность" }, definition: { de: "Integrität bedeutet Übereinstimmung zwischen Werten, Worten und Taten. Eine integre Führungskraft handelt konsequent nach ihren Überzeugungen, auch wenn es unbequem ist — das Fundament von Vertrauen.", en: "Integrity means alignment between values, words, and actions. A leader with integrity acts consistently according to their convictions, even when it is uncomfortable — the foundation of trust.", ru: "Целостность означает соответствие между ценностями, словами и действиями. Целостный лидер действует последовательно по своим убеждениям, даже когда это неудобно — фундамент доверия." }, category: "philosophie", relatedTerms: ["authentische-fuehrung", "ethik", "werte"], relatedServices: ["coaching"] },
  { slug: "sinn", term: { de: "Sinn", en: "Purpose", ru: "Смысл" }, definition: { de: "Sinn ist der tiefere Zweck hinter dem Handeln. Sinnorientierte Führung verbindet persönliche Werte mit beruflichen Zielen und schafft eine kraftvolle Motivationsquelle jenseits von externen Anreizen.", en: "Purpose is the deeper reason behind action. Purpose-oriented leadership connects personal values with professional goals and creates a powerful source of motivation beyond external incentives.", ru: "Смысл — глубокая причина за действиями. Ориентированное на смысл лидерство соединяет личные ценности с профессиональными целями и создаёт мощный источник мотивации за пределами внешних стимулов." }, category: "philosophie", relatedTerms: ["werte", "motivation", "visionaere-fuehrung"], relatedServices: ["coaching", "keynotes"] },
  { slug: "verantwortung", term: { de: "Verantwortung", en: "Responsibility", ru: "Ответственность" }, definition: { de: "Verantwortung zu übernehmen bedeutet, die Konsequenzen des eigenen Handelns bewusst zu tragen. In der bewussten Führung ist Verantwortung kein Druck, sondern eine Quelle von Kraft und Klarheit.", en: "Taking responsibility means consciously bearing the consequences of one's own actions. In conscious leadership, responsibility is not pressure but a source of strength and clarity.", ru: "Принятие ответственности означает осознанно нести последствия собственных действий. В осознанном лидерстве ответственность — не давление, а источник силы и ясности." }, category: "philosophie", relatedTerms: ["autonomie", "ethik", "bewusste-fuehrung"], relatedServices: ["coaching", "corporate"] },
  { slug: "werte", term: { de: "Werte", en: "Values", ru: "Ценности" }, definition: { de: "Werte sind die inneren Leitplanken, die unser Denken und Handeln bestimmen. Bewusste Führung beginnt mit der Klärung der eigenen Werte und ihrer konsequenten Umsetzung im Alltag.", en: "Values are the inner guardrails that determine our thinking and action. Conscious leadership begins with clarifying one's own values and consistently implementing them in everyday life.", ru: "Ценности — внутренние ориентиры, определяющие мышление и действия. Осознанное лидерство начинается с прояснения собственных ценностей и их последовательной реализации в повседневной жизни." }, category: "philosophie", relatedTerms: ["ethik", "integritaet", "sinn"], relatedServices: ["coaching"] },
  { slug: "weisheit", term: { de: "Weisheit", en: "Wisdom", ru: "Мудрость" }, definition: { de: "Weisheit ist die Verbindung von Wissen, Erfahrung und Urteilsvermögen. Sie entsteht durch tiefe Reflexion und ermöglicht Entscheidungen, die über kurzfristigen Nutzen hinausgehen und langfristig Wert schaffen.", en: "Wisdom is the connection of knowledge, experience, and judgment. It arises through deep reflection and enables decisions that go beyond short-term benefit and create long-term value.", ru: "Мудрость — соединение знаний, опыта и рассудительности. Она рождается из глубокой рефлексии и позволяет принимать решения, выходящие за рамки краткосрочной пользы, создавая долгосрочную ценность." }, category: "philosophie", relatedTerms: ["reflexion", "sinn", "bewusstsein"], relatedServices: ["coaching", "keynotes"] },
  { slug: "tugend", term: { de: "Tugend", en: "Virtue", ru: "Добродетель" }, definition: { de: "Tugend beschreibt positive Charaktereigenschaften, die durch bewusste Praxis kultiviert werden. In der Führung sind Tugenden wie Mut, Geduld und Mitgefühl keine Schwäche, sondern Ausdruck wahrer Stärke.", en: "Virtue describes positive character traits cultivated through conscious practice. In leadership, virtues such as courage, patience, and compassion are not weakness but expressions of true strength.", ru: "Добродетель описывает положительные черты характера, культивируемые осознанной практикой. В лидерстве добродетели — мужество, терпение, сострадание — не слабость, а выражение истинной силы." }, category: "philosophie", relatedTerms: ["ethik", "integritaet", "weisheit"], relatedServices: ["coaching"] },
  { slug: "entscheidungsstaerke", term: { de: "Entscheidungsstärke", en: "Decision-Making Strength", ru: "Сила принятия решений" }, definition: { de: "Entscheidungsstärke ist die Fähigkeit, auch in komplexen und unsicheren Situationen klare, durchdachte Entscheidungen zu treffen. Sie basiert auf Klarheit, Selbstkenntnis und dem Vertrauen in die eigene Urteilskraft.", en: "Decision-making strength is the ability to make clear, well-considered decisions even in complex and uncertain situations. It is based on clarity, self-knowledge, and trust in one's own judgment.", ru: "Сила принятия решений — способность принимать ясные, продуманные решения даже в сложных и неопределённых ситуациях. Она основана на ясности, самопознании и доверии к собственному суждению." }, category: "fuehrung", relatedTerms: ["innere-klarheit", "bewusste-fuehrung", "intuition"], relatedServices: ["coaching", "corporate"] },
  { slug: "selbsterkenntnis", term: { de: "Selbsterkenntnis", en: "Self-Knowledge", ru: "Самопознание" }, definition: { de: "Selbsterkenntnis ist die tiefe Kenntnis der eigenen Werte, Stärken, Schwächen und Muster. Sie ist der erste Schritt jeder echten Transformation und bildet das Fundament bewusster Führung.", en: "Self-knowledge is the deep understanding of one's own values, strengths, weaknesses, and patterns. It is the first step of any genuine transformation and forms the foundation of conscious leadership.", ru: "Самопознание — глубокое понимание собственных ценностей, сильных и слабых сторон, паттернов. Это первый шаг любой настоящей трансформации и фундамент осознанного лидерства." }, category: "bewusstsein", relatedTerms: ["selbstbewusstsein", "bewusstseinsentwicklung", "identitaetsarbeit"], relatedServices: ["coaching", "transformation"] },
];

export function getGlossaryBySlug(slug: string): GlossaryEntry | undefined {
  return glossaryEntries.find(e => e.slug === slug);
}

export function getGlossaryByCategory(category: string): GlossaryEntry[] {
  return glossaryEntries.filter(e => e.category === category);
}
